
<template>
  <view class="page-container">
    <!-- 顶部标题栏 -->
    <view class="header">
      <text class="header-title">消息</text>
      <view class="clear-unread cursor-pointer" @click="clearUnread">
        <text>一键清除未读</text>
      </view>
    </view>

    <!-- 主体内容区 -->
    <view class="content-container">
      <!-- 左侧分类导航 -->
      <view class="category-nav">
        <view 
          v-for="(category, index) in categories" 
          :key="index" 
          :class="['category-item cursor-pointer', currentCategory === index ? 'active' : '']"
          @click="switchCategory(index)"
        >
          <text>{{ category }}</text>
        </view>
      </view>

      <!-- 聊天窗口 -->
      <view class="chat-container">
        <scroll-view class="chat-messages" scroll-y ref="chatScrollView">
          <view class="chat-date">
            <text>今天 {{ currentTime }}</text>
          </view>

          <view v-for="(message, index) in messages" :key="index" class="message-item">
            <!-- AI消息 -->
            <view v-if="message.type === 'ai'" class="ai-message">
              <view class="avatar">
                <image :src="aiAvatar" mode="aspectFill"></image>
              </view>
              <view class="message-content">
                <view class="message-bubble">
                  <text>{{ message.content }}</text>
                </view>
                <view class="message-status">
                  <text>{{ message.time }}</text>
                </view>
              </view>
            </view>

            <!-- 用户消息 -->
            <view v-else class="user-message">
              <view class="message-content">
                <view class="message-bubble">
                  <text>{{ message.content }}</text>
                </view>
                <view class="message-status">
                  <text>{{ message.time }} {{ message.read ? '已读' : '未读' }}</text>
                </view>
              </view>
              <view class="avatar">
                <image :src="userAvatar" mode="aspectFill"></image>
              </view>
            </view>
          </view>

          <!-- 常见问题推荐 -->
          <view class="quick-questions">
            <view class="question-title">
              <text>您可能想问：</text>
            </view>
            <scroll-view scroll-x class="questions-scroll">
              <view class="questions-container">
                <view 
                  v-for="(question, index) in commonQuestions" 
                  :key="index" 
                  class="question-item cursor-pointer"
                  @click="sendQuestion(question)"
                >
                  <text>{{ question }}</text>
                </view>
              </view>
            </scroll-view>
          </view>

          <!-- 人工客服状态 -->
          <view v-if="humanServiceActive" class="human-service-status">
            <uni-icons type="staff" size="20" color="#4CAF50"></uni-icons>
            <text>正在接入人工客服，请稍候...</text>
          </view>
        </scroll-view>

        <!-- 底部输入框 -->
        <view class="input-container">
          <view class="input-tools">
            <uni-icons type="image" size="24" color="#666666" class="cursor-pointer"></uni-icons>
            <uni-icons type="camera" size="24" color="#666666" class="cursor-pointer"></uni-icons>
            <uni-icons type="mic-filled" size="24" color="#666666" class="cursor-pointer"></uni-icons>
          </view>
          <view class="input-box">
            <input 
              type="text" 
              v-model="inputMessage" 
              placeholder="请输入您的问题" 
              confirm-type="send"
              @confirm="sendMessage"
            />
            <view class="send-btn cursor-pointer" @click="sendMessage">
              <text>发送</text>
            </view>
          </view>
        </view>
      </view>
    </view>

    <!-- 底部导航栏 -->
    <view class="tab-bar">
      <view 
        v-for="(tab, index) in tabs" 
        :key="index" 
        :class="['tab-item cursor-pointer', currentTab === index ? 'active' : '']"
        @click="switchTab(index)"
      >
        <uni-icons :type="tab.icon" size="24" :color="currentTab === index ? '#4CAF50' : '#666666'"></uni-icons>
        <text>{{ tab.name }}</text>
      </view>
    </view>
  </view>
</template>
<script lang="ts" setup>
import { ref, onMounted } from 'vue';

// 头像图片
const aiAvatar = 'https://readdy.ai/api/search-image?query=3D%20cartoon%2C%20AI%20assistant%20robot%20with%20friendly%20face%2C%20subject%20fills%2080%20percent%20of%20frame%2C%20vibrant%20colors%20with%20soft%20gradients%2C%20minimalist%20design%2C%20smooth%20rounded%20shapes%2C%20subtle%20shading%2C%20no%20outlines%2C%20centered%20composition%2C%20isolated%20on%20white%20background%2C%20playful%20and%20friendly%20aesthetic%2C%20high%20detail%20quality%2C%20clean%20and%20modern%20look&width=100&height=100&seq=1001&orientation=squarish';
const userAvatar = 'https://readdy.ai/api/search-image?query=3D%20cartoon%2C%20simple%20user%20avatar%20icon%2C%20subject%20fills%2080%20percent%20of%20frame%2C%20vibrant%20colors%20with%20soft%20gradients%2C%20minimalist%20design%2C%20smooth%20rounded%20shapes%2C%20subtle%20shading%2C%20no%20outlines%2C%20centered%20composition%2C%20isolated%20on%20white%20background%2C%20playful%20and%20friendly%20aesthetic%2C%20high%20detail%20quality%2C%20clean%20and%20modern%20look&width=100&height=100&seq=1002&orientation=squarish';

// 分类数据
const categories = ref(['农产品', '饲料', '养生保健类']);
const currentCategory = ref(0);

// 底部导航数据
const tabs = ref([
  { name: '首页', icon: 'home' },
  { name: '商品', icon: 'list' },
  { name: '消息', icon: 'chat' },
  { name: '购物车', icon: 'cart' },
  { name: '我的', icon: 'person' }
]);
const currentTab = ref(2); // 默认选中消息

// 聊天数据
const messages = ref([
  { 
    type: 'ai', 
    content: '您好，我是智能客服小农，很高兴为您服务。请问有什么可以帮助您的吗？', 
    time: '10:30', 
    read: true 
  },
  { 
    type: 'user', 
    content: '我想了解一下有机蔬菜的配送时间', 
    time: '10:31', 
    read: true 
  },
  { 
    type: 'ai', 
    content: '您好，我们的有机蔬菜一般在下单后24小时内配送，如果您是会员可以享受优先配送服务，最快可在4小时内送达。', 
    time: '10:31', 
    read: true 
  },
  { 
    type: 'user', 
    content: '我想咨询一下关于饲料的问题', 
    time: '10:32', 
    read: true 
  },
  { 
    type: 'ai', 
    content: '好的，请问您想了解哪类饲料的信息呢？我们有猪饲料、鸡饲料、牛饲料等多种类型，也有针对不同生长阶段的特殊配方。', 
    time: '10:33', 
    read: false 
  }
]);

// 常见问题
const commonQuestions = ref([
  '如何查看订单状态？',
  '退换货政策是什么？',
  '会员有什么特权？',
  '如何联系人工客服？',
  '配送范围有哪些？'
]);

// 输入框内容
const inputMessage = ref('');
// 人工客服状态
const humanServiceActive = ref(false);
// 当前时间
const currentTime = ref('14:25');
// 聊天窗口ref
const chatScrollView = ref(null);

// 发送消息
const sendMessage = () => {
  if (!inputMessage.value.trim()) return;
  
  // 添加用户消息
  messages.value.push({
    type: 'user',
    content: inputMessage.value,
    time: getCurrentTime(),
    read: false
  });
  
  // 检查是否请求人工客服
  if (inputMessage.value.includes('人工') || inputMessage.value.includes('客服')) {
    humanServiceActive.value = true;
    setTimeout(() => {
      messages.value.push({
        type: 'ai',
        content: '您好，人工客服已接入，我是客服小李，很高兴为您服务！',
        time: getCurrentTime(),
        read: false
      });
    }, 2000);
  } else {
    // AI回复
    setTimeout(() => {
      messages.value.push({
        type: 'ai',
        content: getAIResponse(inputMessage.value),
        time: getCurrentTime(),
        read: false
      });
    }, 1000);
  }
  
  // 清空输入框
  inputMessage.value = '';
  
  // 滚动到底部
  setTimeout(() => {
    scrollToBottom();
  }, 100);
};

// 发送预设问题
const sendQuestion = (question: string) => {
  inputMessage.value = question;
  sendMessage();
};

// 获取AI回复
const getAIResponse = (question: string) => {
  if (question.includes('订单')) {
    return '您可以在"我的"-"我的订单"中查看所有订单状态，包括待付款、待发货、待收货等。';
  } else if (question.includes('退换货') || question.includes('退款')) {
    return '我们支持7天无理由退换货，食品类商品需要未拆封，非质量问题运费由买家承担。';
  } else if (question.includes('会员')) {
    return '会员可享受专属折扣、生日礼包、优先配送、积分翻倍等特权，详情可查看会员中心。';
  } else if (question.includes('配送')) {
    return '我们目前覆盖全国300多个城市，具体配送时间和范围可在下单时查看。';
  } else {
    return '感谢您的咨询，我们的农产品均来自自有基地，保证新鲜和品质。您还有其他问题吗？';
  }
};

// 获取当前时间
const getCurrentTime = () => {
  const now = new Date();
  const hours = now.getHours().toString().padStart(2, '0');
  const minutes = now.getMinutes().toString().padStart(2, '0');
  return `${hours}:${minutes}`;
};

// 滚动到底部
const scrollToBottom = () => {
  if (chatScrollView.value) {
    const query = uni.createSelectorQuery().in(this);
    query.select('.chat-messages').boundingClientRect();
    query.exec((res) => {
      if (res && res[0]) {
        uni.pageScrollTo({
          scrollTop: res[0].height,
          duration: 300
        });
      }
    });
  }
};

// 切换分类
const switchCategory = (index: number) => {
  currentCategory.value = index;
};

// 切换底部导航
const switchTab = (index: number) => {
  currentTab.value = index;
};

// 清除未读
const clearUnread = () => {
  messages.value.forEach(msg => {
    msg.read = true;
  });
};

// 页面加载完成后滚动到底部
onMounted(() => {
  scrollToBottom();
  // 设置当前时间
  const now = new Date();
  const hours = now.getHours().toString().padStart(2, '0');
  const minutes = now.getMinutes().toString().padStart(2, '0');
  currentTime.value = `${hours}:${minutes}`;
});
</script>
